// src/components/Navbar.jsx
import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';

const Navbar = () => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileOpen, setMobileOpen] = useState(false);
  const location = useLocation();

  useEffect(() => {
    const handleScroll = () => {
      setScrolled(window.scrollY > 50);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    setMobileOpen(false);
  }, [location]);

  const navLinks = [
    { path: '/', label: 'Home' },
    { path: '/project', label: 'Projects' },
    { path: '/admin', label: 'Admin' },
  ];

  return (
    <>
      <motion.nav
        initial={{ y: -100 }}
        animate={{ y: 0 }}
        transition={{ duration: 0.6, ease: [0.34, 1.56, 0.64, 1] }}
        className={`navbar-fixed ${scrolled ? 'navbar-scrolled' : ''}`}
      >
        <div className="navbar-container">
          <Link to="/" className="navbar-logo">
            <span className="logo-text">HS</span>
            <span className="logo-dot"></span>
          </Link>

          <div className="navbar-desktop">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`nav-link ${location.pathname === link.path ? 'active' : ''}`}
              >
                {link.label}
                {location.pathname === link.path && (
                  <motion.span
                    layoutId="navIndicator"
                    className="nav-indicator"
                    transition={{ type: 'spring', duration: 0.5 }}
                  />
                )}
              </Link>
            ))}
          </div>

          <button
            className="navbar-mobile-toggle"
            onClick={() => setMobileOpen(!mobileOpen)}
            aria-label="Toggle menu"
          >
            <span className={`hamburger ${mobileOpen ? 'active' : ''}`} />
          </button>
        </div>
      </motion.nav>

      <AnimatePresence>
        {mobileOpen && (
          <motion.div
            initial={{ opacity: 0, y: -20 }}
            animate={{ opacity: 1, y: 0 }}
            exit={{ opacity: 0, y: -20 }}
            transition={{ duration: 0.3 }}
            className="navbar-mobile-menu"
          >
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`mobile-nav-link ${location.pathname === link.path ? 'active' : ''}`}
                onClick={() => setMobileOpen(false)}
              >
                {link.label}
              </Link>
            ))}
          </motion.div>
        )}
      </AnimatePresence>

      <style>{`
        .navbar-fixed {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          z-index: 1000;
          padding: 1rem 2rem;
          transition: all 0.4s cubic-bezier(0.34, 1.56, 0.64, 1);
        }

        .navbar-scrolled {
          background: rgba(9, 9, 9, 0.85);
          backdrop-filter: blur(20px) saturate(1.8);
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
          padding: 0.7rem 2rem;
        }

        .navbar-container {
          max-width: 1200px;
          margin: 0 auto;
          display: flex;
          justify-content: space-between;
          align-items: center;
        }

        .navbar-logo {
          display: flex;
          align-items: center;
          gap: 6px;
          text-decoration: none;
          position: relative;
        }

        .logo-text {
          font-family: 'Space Grotesk', sans-serif;
          font-size: 1.6rem;
          font-weight: 700;
          color: #F4F4F4;
          letter-spacing: -1px;
          background: linear-gradient(135deg, #FF3EA5, #FF7CC7);
          -webkit-background-clip: text;
          -webkit-text-fill-color: transparent;
          background-clip: text;
        }

        .logo-dot {
          width: 6px;
          height: 6px;
          border-radius: 50%;
          background: #FF3EA5;
          display: inline-block;
          animation: pulse-dot 2s ease-in-out infinite;
        }

        @keyframes pulse-dot {
          0%, 100% { opacity: 1; transform: scale(1); }
          50% { opacity: 0.4; transform: scale(0.6); }
        }

        .navbar-desktop {
          display: flex;
          gap: 2rem;
          align-items: center;
        }

        .nav-link {
          position: relative;
          color: #A0A0A0;
          text-decoration: none;
          font-family: 'Inter', sans-serif;
          font-size: 0.9rem;
          font-weight: 500;
          padding: 0.4rem 0;
          transition: color 0.3s ease;
        }

        .nav-link:hover {
          color: #F4F4F4;
        }

        .nav-link.active {
          color: #F4F4F4;
        }

        .nav-indicator {
          position: absolute;
          bottom: -2px;
          left: 0;
          right: 0;
          height: 2px;
          background: linear-gradient(90deg, #FF3EA5, #FF7CC7);
          border-radius: 2px;
        }

        .navbar-mobile-toggle {
          display: none;
          background: none;
          border: none;
          cursor: pointer;
          padding: 0.5rem;
          z-index: 1001;
        }

        .hamburger {
          display: block;
          width: 24px;
          height: 2px;
          background: #F4F4F4;
          position: relative;
          transition: all 0.3s ease;
        }

        .hamburger::before,
        .hamburger::after {
          content: '';
          position: absolute;
          width: 24px;
          height: 2px;
          background: #F4F4F4;
          transition: all 0.3s ease;
        }

        .hamburger::before {
          top: -7px;
        }

        .hamburger::after {
          bottom: -7px;
        }

        .hamburger.active {
          background: transparent;
        }

        .hamburger.active::before {
          transform: rotate(45deg);
          top: 0;
        }

        .hamburger.active::after {
          transform: rotate(-45deg);
          bottom: 0;
        }

        .navbar-mobile-menu {
          position: fixed;
          top: 0;
          left: 0;
          right: 0;
          background: rgba(9, 9, 9, 0.98);
          backdrop-filter: blur(20px);
          padding: 5rem 2rem 2rem;
          display: flex;
          flex-direction: column;
          gap: 1.5rem;
          z-index: 999;
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
        }

        .mobile-nav-link {
          color: #A0A0A0;
          text-decoration: none;
          font-family: 'Inter', sans-serif;
          font-size: 1.4rem;
          font-weight: 600;
          padding: 0.5rem 0;
          transition: color 0.3s ease;
          border-bottom: 1px solid rgba(255, 255, 255, 0.05);
        }

        .mobile-nav-link:hover,
        .mobile-nav-link.active {
          color: #F4F4F4;
        }

        @media (max-width: 768px) {
          .navbar-fixed {
            padding: 0.8rem 1rem;
          }

          .navbar-scrolled {
            padding: 0.5rem 1rem;
          }

          .navbar-desktop {
            display: none;
          }

          .navbar-mobile-toggle {
            display: block;
          }

          .logo-text {
            font-size: 1.3rem;
          }
        }
      `}</style>
    </>
  );
};

export default Navbar;
